import { Pipe, PipeTransform } from '@angular/core';
import { LocalizedText } from '../interfaces/localized-text.interface';

@Pipe({
  name: 'localizedText',
  standalone: true
})
export class LocalizedTextPipe implements PipeTransform {
  transform(value: LocalizedText | null | undefined, language: 'it' | 'en' = 'it'): string {
    if (!value) {
      return '';
    }

    return value[language] || value.it || '';
  }
}
