import { CurrencyPipe } from '@angular/common';
import { Component, Input } from '@angular/core';
import { RouterLink } from '@angular/router';
import { Artwork, ArtworkStatus } from '../../interfaces/artwork.interface';
import { LocalizedTextPipe } from '../../pipes/localized-text.pipe';

@Component({
  selector: 'app-artwork-card',
  standalone: true,
  imports: [CurrencyPipe, RouterLink, LocalizedTextPipe],
  templateUrl: './artwork-card.component.html',
  styleUrl: './artwork-card.component.sass'
})
export class ArtworkCardComponent {
  @Input({ required: true }) artwork!: Artwork;
  @Input() language: 'it' | 'en' = 'it';
  @Input() showStatus = true;
  @Input() variant: 'grid' | 'editorial' = 'grid';

  protected get artworkLink(): string[] {
    return this.language === 'it'
      ? ['/it/opere', this.artwork.slug]
      : ['/en/artworks', this.artwork.slug];
  }

  protected getStatusLabel(status: ArtworkStatus): string {
    const italianLabels: Record<ArtworkStatus, string> = {
      available: 'Disponibile',
      sold: 'Venduta',
      reserved: 'Riservata',
      private_collection: 'Collezione privata',
      not_available: 'Non disponibile'
    };

    const englishLabels: Record<ArtworkStatus, string> = {
      available: 'Available',
      sold: 'Sold',
      reserved: 'Reserved',
      private_collection: 'Private Collection',
      not_available: 'Not Available'
    };

    return this.language === 'it' ? italianLabels[status] : englishLabels[status];
  }

  protected get isAvailable(): boolean {
    return this.artwork.status === 'available';
  }

  protected get isSold(): boolean {
    return this.artwork.status === 'sold';
  }

  protected get shouldShowMetaRow(): boolean {
    return this.showStatus || Boolean(this.artwork.price.visible && this.artwork.price.amount);
  }

  protected get auctionPill(): string | null {
    if (!this.artwork.auction) {
      return null;
    }

    if (this.artwork.auction.publicStatus === 'live') {
      return this.language === 'it' ? 'In asta' : 'At auction';
    }

    if (this.artwork.auction.publicStatus === 'upcoming') {
      return this.language === 'it' ? 'Asta in arrivo' : 'Auction soon';
    }

    return this.language === 'it' ? 'Asta conclusa' : 'Auction closed';
  }
}
